import React, { useState } from 'react';
import { Package, CheckCircle, Clock, Trash2, AlertCircle, ChevronRight, CircleDollarSign, Send, Zap, Copy, ExternalLink, ChevronDown, ChevronUp, Mail, Key, ShieldAlert } from 'lucide-react';
import { Order } from '../types.ts';

interface AdminDashboardProps {
  isOpen: boolean;
  orders: Order[];
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onDeleteOrder: (id: string) => void;
  onAddBalance: (amount: number) => void;
  onClose: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ isOpen, orders, onUpdateStatus, onDeleteOrder, onAddBalance, onClose }) => {
  const [activeTab, setActiveTab] = useState<'orders' | 'balance'>('orders');
  const [balanceAmount, setBalanceAmount] = useState('');
  const [expandedOrderId, setExpandedOrderId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const handleAddBalance = () => {
    const amount = parseFloat(balanceAmount);
    if (!isNaN(amount) && amount > 0) {
      onAddBalance(amount);
      setBalanceAmount('');
      setActiveTab('orders');
    } else {
      alert("সঠিক টাকার অংক লিখুন!");
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const parseCredentials = (details: string) => {
    // Regex to extract data from the markdown-style details string
    const gmailMatch = details.match(/📧 \*\*Gmail:\*\* `([^`]+)`/);
    const passMatch = details.match(/🔑 \*\*Pass:\*\* `([^`]+)`/);
    const recoveryMatch = details.match(/🛡️ \*\*Recovery:\*\* `([^`]+)`/);

    return {
      gmail: gmailMatch ? gmailMatch[1] : 'N/A',
      password: passMatch ? passMatch[1] : 'N/A',
      recovery: recoveryMatch ? recoveryMatch[1] : 'N/A'
    };
  };

  return (
    <>
      <div 
        className={`fixed inset-0 z-[60] bg-black/60 backdrop-blur-sm transition-opacity duration-300 ${
          isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'
        }`}
        onClick={onClose}
      />

      <div 
        className={`fixed top-0 right-0 h-full z-[70] w-full max-w-4xl bg-white shadow-2xl transition-transform duration-500 ease-in-out transform ${
          isOpen ? 'translate-x-0' : 'translate-x-full'
        }`}
      >
        <div className="h-full flex flex-col">
          <div className="p-6 border-b border-gray-100 flex items-center justify-between bg-slate-50/50">
            <div className="flex items-center gap-4">
              <button 
                onClick={onClose}
                className="p-2 hover:bg-gray-100 rounded-xl transition-colors text-gray-400 hover:text-gray-900"
              >
                <ChevronRight className="w-6 h-6" />
              </button>
              <div>
                <h1 className="text-2xl font-black text-gray-900">Admin Panel</h1>
                <p className="text-xs text-indigo-600 font-bold uppercase tracking-widest">Management System v2.0</p>
              </div>
            </div>

            <div className="flex gap-2 p-1 bg-slate-200/50 rounded-2xl">
              <button 
                onClick={() => setActiveTab('orders')}
                className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'orders' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}
              >
                Orders
              </button>
              <button 
                onClick={() => setActiveTab('balance')}
                className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'balance' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500'}`}
              >
                Add Money
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 md:p-6">
            {activeTab === 'orders' ? (
              <>
                {orders.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-center">
                    <div className="p-8 bg-slate-50 rounded-full mb-6">
                      <Clock className="w-16 h-16 text-slate-200" />
                    </div>
                    <h3 className="text-xl font-bold text-slate-900">পেন্ডিং কোনো কাজ নেই</h3>
                  </div>
                ) : (
                  <div className="border border-slate-100 rounded-3xl overflow-hidden shadow-sm bg-white">
                    <table className="w-full text-left table-fixed">
                      <thead className="bg-slate-50/80 border-b border-slate-100">
                        <tr>
                          <th className="w-1/3 px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Service</th>
                          <th className="w-1/4 px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Customer</th>
                          <th className="w-1/4 px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                          <th className="w-[120px] px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Action</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-50">
                        {orders.map((order) => {
                          const isExpanded = expandedOrderId === order.id;
                          const creds = order.serviceId === 'gmail-sell' ? parseCredentials(order.details) : null;

                          return (
                            <React.Fragment key={order.id}>
                              <tr 
                                className={`transition-colors cursor-pointer ${isExpanded ? 'bg-indigo-50/30' : 'hover:bg-slate-50/30'} group`}
                                onClick={() => setExpandedOrderId(isExpanded ? null : order.id)}
                              >
                                <td className="px-6 py-5">
                                  <div className="flex flex-col">
                                    <div className="flex items-center gap-2">
                                      <span className="font-bold text-slate-900 text-sm">{order.serviceName}</span>
                                      {creds && <Zap className="w-3 h-3 text-amber-500 fill-amber-500" />}
                                    </div>
                                    <span className="text-[10px] text-slate-400">{new Date(order.createdAt).toLocaleTimeString()}</span>
                                  </div>
                                </td>
                                <td className="px-6 py-5">
                                  <span className="text-sm font-bold text-slate-900 truncate block">{order.customerName}</span>
                                </td>
                                <td className="px-6 py-5">
                                  <div onClick={(e) => e.stopPropagation()}>
                                    <select 
                                      value={order.status}
                                      onChange={(e) => onUpdateStatus(order.id, e.target.value as Order['status'])}
                                      className={`text-[10px] font-black px-3 py-1.5 rounded-full border-none focus:ring-2 focus:ring-indigo-100 cursor-pointer uppercase tracking-widest shadow-sm ${
                                        order.status === 'pending' ? 'bg-amber-100 text-amber-700' : 
                                        order.status === 'completed' ? 'bg-green-100 text-green-700' : 
                                        'bg-rose-100 text-rose-700'
                                      }`}
                                    >
                                      <option value="pending">Pending</option>
                                      <option value="completed">Approved</option>
                                      <option value="cancelled">Reject</option>
                                    </select>
                                  </div>
                                </td>
                                <td className="px-6 py-5 text-right">
                                  <div className="flex items-center justify-end gap-1">
                                    <button 
                                      className="p-2 text-slate-400 hover:text-indigo-600 transition-colors"
                                    >
                                      {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                                    </button>
                                    <button 
                                      onClick={(e) => {
                                        e.stopPropagation();
                                        onDeleteOrder(order.id);
                                      }}
                                      className="p-2 text-slate-200 hover:text-rose-600 transition-colors opacity-0 group-hover:opacity-100"
                                    >
                                      <Trash2 className="w-4 h-4" />
                                    </button>
                                  </div>
                                </td>
                              </tr>
                              {isExpanded && (
                                <tr className="bg-indigo-50/40 animate-in slide-in-from-top-2 duration-200">
                                  <td colSpan={4} className="px-6 py-6 border-t border-indigo-100/50">
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                      <div className="space-y-4">
                                        <div className="flex items-center gap-2 mb-2">
                                          <AlertCircle className="w-4 h-4 text-indigo-500" />
                                          <span className="text-xs font-black text-indigo-900 uppercase tracking-widest">Submission Details</span>
                                        </div>

                                        {creds ? (
                                          <div className="space-y-3">
                                            <div className="bg-white p-4 rounded-2xl border border-indigo-100 shadow-sm flex items-center justify-between group/row">
                                              <div className="flex items-center gap-3">
                                                <div className="bg-indigo-50 p-2 rounded-lg"><Mail className="w-4 h-4 text-indigo-600" /></div>
                                                <div>
                                                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gmail</p>
                                                  <p className="text-sm font-mono font-bold text-slate-700">{creds.gmail}</p>
                                                </div>
                                              </div>
                                              <button 
                                                onClick={() => copyToClipboard(creds.gmail, order.id + 'gmail')}
                                                className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                                              >
                                                {copiedId === order.id + 'gmail' ? <CheckCircle className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                                              </button>
                                            </div>

                                            <div className="bg-white p-4 rounded-2xl border border-indigo-100 shadow-sm flex items-center justify-between group/row">
                                              <div className="flex items-center gap-3">
                                                <div className="bg-indigo-50 p-2 rounded-lg"><Key className="w-4 h-4 text-indigo-600" /></div>
                                                <div>
                                                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Password</p>
                                                  <p className="text-sm font-mono font-bold text-slate-700">{creds.password}</p>
                                                </div>
                                              </div>
                                              <button 
                                                onClick={() => copyToClipboard(creds.password, order.id + 'pass')}
                                                className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                                              >
                                                {copiedId === order.id + 'pass' ? <CheckCircle className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
