const AdminDashboard: React.FC<AdminDashboardProps> = ({ isOpen, orders, onUpdateStatus, onDeleteOrder, onClose }) => {
  const [expandedOrderId, setExpandedOrderId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const parseCredentials = (details: string) => {
    const gmailMatch = details.match(/📧 \*\*Gmail:\*\* `([^`]+)`/);
    const passMatch = details.match(/🔑 \*\*Pass:\*\* `([^`]+)`/);
    const recoveryMatch = details.match(/🛡️ \*\*Recovery:\*\* `([^`]+)`/);

    return {
      gmail: gmailMatch ? gmailMatch[1] : 'N/A',
      password: passMatch ? passMatch[1] : 'N/A',
      recovery: recoveryMatch ? recoveryMatch[1] : 'N/A'
    };
  };

  return (
    <>
      <div 
        className={`fixed inset-0 z-[60] bg-black/60 backdrop-blur-sm transition-opacity duration-300 ${
          isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'
        }`}
        onClick={onClose}
      />

      <div 
        className={`fixed top-0 right-0 h-full z-[70] w-full max-w-4xl bg-white shadow-2xl transition-transform duration-500 ease-in-out transform ${
          isOpen ? 'translate-x-0' : 'translate-x-full'
        }`}
      >
        <div className="h-full flex flex-col">
          <div className="p-6 border-b border-gray-100 flex items-center justify-between bg-slate-50/50">
            <div className="flex items-center gap-4">
              <button 
                onClick={onClose}
                className="p-2 hover:bg-gray-100 rounded-xl transition-colors text-gray-400 hover:text-gray-900"
              >
                <ChevronRight className="w-6 h-6" />
              </button>
              <div>
                <h1 className="text-2xl font-black text-gray-900">Admin Panel</h1>
                <p className="text-xs text-indigo-600 font-bold uppercase tracking-widest">Management System v2.0</p>
              </div>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 md:p-6">
            {orders.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-center">
                <div className="p-8 bg-slate-50 rounded-full mb-6">
                  <Clock className="w-16 h-16 text-slate-200" />
                </div>
                <h3 className="text-xl font-bold text-slate-900">পেন্ডিং কোনো কাজ নেই</h3>
              </div>
            ) : (
              <div className="border border-slate-100 rounded-3xl overflow-hidden shadow-sm bg-white">
                <table className="w-full text-left table-fixed">
                  <thead className="bg-slate-50/80 border-b border-slate-100">
                    <tr>
                      <th className="w-1/3 px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Service</th>
                      <th className="w-1/4 px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Customer</th>
                      <th className="w-1/4 px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                      <th className="w-[120px] px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Action</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {orders.map((order) => {
                      const isExpanded = expandedOrderId === order.id;
                      const creds = order.serviceId === 'gmail-sell' ? parseCredentials(order.details) : null;

                      return (
                        <React.Fragment key={order.id}>
                          <tr 
                            className={`transition-colors cursor-pointer ${isExpanded ? 'bg-indigo-50/30' : 'hover:bg-slate-50/30'} group`}
                            onClick={() => setExpandedOrderId(isExpanded ? null : order.id)}
                          >
                            <td className="px-6 py-5">
                              <div className="flex flex-col">
                                <div className="flex items-center gap-2">
                                  <span className="font-bold text-slate-900 text-sm">{order.serviceName}</span>
                                  {creds && <Zap className="w-3 h-3 text-amber-500 fill-amber-500" />}
                                </div>
                                <span className="text-[10px] text-slate-400">{new Date(order.createdAt).toLocaleTimeString()}</span>
                              </div>
                            </td>
                            <td className="px-6 py-5">
                              <span className="text-sm font-bold text-slate-900 truncate block">{order.customerName}</span>
                            </td>
                            <td className="px-6 py-5">
                              <div onClick={(e) => e.stopPropagation()}>
                                <select 
                                  value={order.status}
                                  onChange={(e) => onUpdateStatus(order.id, e.target.value as Order['status'])}
                                  className={`text-[10px] font-black px-3 py-1.5 rounded-full border-none focus:ring-2 focus:ring-indigo-100 cursor-pointer uppercase tracking-widest shadow-sm ${
                                    order.status === 'pending' ? 'bg-amber-100 text-amber-700' : 
                                    order.status === 'completed' ? 'bg-green-100 text-green-700' : 
                                    'bg-rose-100 text-rose-700'
                                  }`}
                                >
                                  <option value="pending">Pending</option>
                                  <option value="completed">Approved</option>
                                  <option value="cancelled">Reject</option>
                                </select>
                              </div>
                            </td>
                            <td className="px-6 py-5 text-right">
                              <div className="flex items-center justify-end gap-1">
                                <button 
                                  className="p-2 text-slate-400 hover:text-indigo-600 transition-colors"
                                >
                                  {isExpanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                                </button>
                                <button 
                                  onClick={(e) => {
                                    e.stopPropagation();
                                    onDeleteOrder(order.id);
                                  }}
                                  className="p-2 text-slate-200 hover:text-rose-600 transition-colors opacity-0 group-hover:opacity-100"
                                >
                                  <Trash2 className="w-4 h-4" />
                                </button>
                              </div>
                            </td>
                          </tr>
                          {isExpanded && (
                            <tr className="bg-indigo-50/40 animate-in slide-in-from-top-2 duration-200">
                              <td colSpan={4} className="px-6 py-6 border-t border-indigo-100/50">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                  <div className="space-y-4">
                                    <div className="flex items-center gap-2 mb-2">
                                      <AlertCircle className="w-4 h-4 text-indigo-500" />
                                      <span className="text-xs font-black text-indigo-900 uppercase tracking-widest">Submission Details</span>
                                    </div>

                                    {creds ? (
                                      <div className="space-y-3">
                                        <div className="bg-white p-4 rounded-2xl border border-indigo-100 shadow-sm flex items-center justify-between group/row">
                                          <div className="flex items-center gap-3">
                                            <div className="bg-indigo-50 p-2 rounded-lg"><Mail className="w-4 h-4 text-indigo-600" /></div>
                                            <div>
                                              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gmail</p>
                                              <p className="text-sm font-mono font-bold text-slate-700">{creds.gmail}</p>
                                            </div>
                                          </div>
                                          <button 
                                            onClick={() => copyToClipboard(creds.gmail, order.id + 'gmail')}
                                            className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                                          >
                                            {copiedId === order.id + 'gmail' ? <CheckCircle className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                                          </button>
                                        </div>

                                        <div className="bg-white p-4 rounded-2xl border border-indigo-100 shadow-sm flex items-center justify-between group/row">
                                          <div className="flex items-center gap-3">
                                            <div className="bg-indigo-50 p-2 rounded-lg"><Key className="w-4 h-4 text-indigo-600" /></div>
                                            <div>
                                              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Password</p>
                                              <p className="text-sm font-mono font-bold text-slate-700">{creds.password}</p>
                                            </div>
                                          </div>
                                          <button 
                                            onClick={() => copyToClipboard(creds.password, order.id + 'pass')}
                                            className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                                          >
                                            {copiedId === order.id + 'pass' ? <CheckCircle className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                                          </button>
                                        </div>

                                        <div className="bg-white p-4 rounded-2xl border border-indigo-100 shadow-sm flex items-center justify-between group/row">
                                          <div className="flex items-center gap-3">
                                            <div className="bg-indigo-50 p-2 rounded-lg"><ShieldAlert className="w-4 h-4 text-indigo-600" /></div>
                                            <div>
                                              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Recovery</p>
                                              <p className="text-sm font-mono font-bold text-slate-700">{creds.recovery}</p>
                                            </div>
                                          </div>
                                          <button 
                                            onClick={() => copyToClipboard(creds.recovery, order.id + 'rec')}
                                            className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                                          >
                                            {copiedId === order.id + 'rec' ? <CheckCircle className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
                                          </button>
                                        </div>
                                      </div>
                                    ) : (
                                      <div className="bg-white p-5 rounded-2xl border border-indigo-100 text-sm text-slate-500 leading-relaxed italic">
                                        {order.details}
                                      </div>
                                    )}
                                  </div>

                                  <div className="space-y-4">
                                    <div className="flex items-center gap-2 mb-2">
                                      <Landmark className="w-4 h-4 text-slate-500" />
                                      <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Metadata</span>
                                    </div>
                                    <div className="bg-white p-5 rounded-2xl border border-slate-100 space-y-3">
                                      <div className="flex justify-between">
                                        <span className="text-xs font-bold text-slate-400">Order ID:</span>
                                        <span className="text-xs font-mono font-bold text-slate-900">#{order.id}</span>
                                      </div>
                                      <div className="flex justify-between">
                                        <span className="text-xs font-bold text-slate-400">Customer Handle:</span>
                                        <span className="text-xs font-bold text-indigo-600">{order.customerHandle}</span>
                                      </div>
                                      <div className="flex justify-between">
                                        <span className="text-xs font-bold text-slate-400">Date/Time:</span>
                                        <span className="text-xs font-bold text-slate-900">{new Date(order.createdAt).toLocaleString()}</span>
                                      </div>
                                      <div className="pt-3 border-t flex gap-2">
                                        <button 
                                          onClick={() => onUpdateStatus(order.id, 'completed')}
                                          className="flex-1 py-2 bg-green-500 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-green-600 transition-colors"
                                        >
                                          Approve
                                        </button>
                                        <button 
                                          onClick={() => onUpdateStatus(order.id, 'cancelled')}
                                          className="flex-1 py-2 bg-rose-500 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-600 transition-colors"
                                        >
                                          Reject
                                        </button>
                                      </div>
                                    </div>
                                  </div>
                                </div>
                              </td>
                            </tr>
                          )}
                        </React.Fragment>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>

          <div className="p-6 border-t border-gray-100 bg-slate-50/50">
             <div className="flex items-center justify-between">
                <div className="flex flex-col">
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Mahabub Admin Command</p>
                   <p className="text-xs font-bold text-indigo-600">Secure Protocol v2.1</p>
                </div>
                <button 
                  onClick={onClose}
                  className="px-6 py-2.5 bg-slate-900 text-white rounded-xl text-sm font-bold hover:bg-slate-800 transition-all shadow-lg"
                >
                  Close Panel
                </button>
             </div>
          </div>
        </div>
      </div>
    </>
  );
}; export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import SupportBot from './components/SupportBot.tsx';
import TelegramDashboard from './components/TelegramDashboard.tsx';
import TaskAssignment from './components/TaskAssignment.tsx';
import WelcomeMessage from './components/WelcomeMessage.tsx';
import Login from './components/Login.tsx';
import { AccountModal, ReferralModal, PricesModal } from './components/Modals.tsx';
import { Order, ViewState, Task } from './types.ts';
import { Star, Zap, CheckCircle, X, Ban } from 'lucide-react';

const App: React.FC = () => {
  const [userName, setUserName] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<ViewState>('store');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [orders, setOrders] = useState<Order[]>([]);
  const [usedGmails, setUsedGmails] = useState<string[]>([]);

  const [showToast, setShowToast] = useState(false);
  const [toastType, setToastType] = useState<'success' | 'cancel'>('success');
  const [toastMessage, setToastMessage] = useState({ title: '', sub: '', detail: '' });

  // Task state
  const [activeTask, setActiveTask] = useState<Task | null>(null);
  const [showWelcome, setShowWelcome] = useState(false);

  // Chat integration state
  const [isChatVisible, setIsChatVisible] = useState(false);
  const [chatInitialMessage, setChatInitialMessage] = useState('');

  // Modal states
  const [isAccountOpen, setIsAccountOpen] = useState(false);
  const [isReferralOpen, setIsReferralOpen] = useState(false);
  const [isPricesOpen, setIsPricesOpen] = useState(false);

  // Updated Constants
  const SUBMISSION_CHANNEL_LINK = "https://t.me/+R6VyXUcmkZg2YjNl";
  const WHATSAPP_GROUP_URL = "https://chat.whatsapp.com/G07De5sgX8IKOldlP1NeGc?mode=gi_t";

  useEffect(() => {
    const savedName = localStorage.getItem('croma_user_name');
    if (savedName) setUserName(savedName);

    const savedOrders = localStorage.getItem('croma_orders');
    if (savedOrders) setOrders(JSON.parse(savedOrders));

    const savedGmails = localStorage.getItem('croma_used_gmails');
    if (savedGmails) setUsedGmails(JSON.parse(savedGmails));
  }, []);

  useEffect(() => {
    localStorage.setItem('croma_orders', JSON.stringify(orders));
  }, [orders]);

  useEffect(() => {
    localStorage.setItem('croma_used_gmails', JSON.stringify(usedGmails));
  }, [usedGmails]);

  const handleLogin = (name: string) => {
    setUserName(name);
    localStorage.setItem('croma_user_name', name);
  };

  const handleSellClick = () => {
    setShowWelcome(true);
    setActiveTask(null);
    setIsChatVisible(false);
  };

  const generateNewTask = () => {
    const firstNames = ['Cory', 'Ryan', 'Liam', 'Noah', 'James', 'Oliver', 'Lucas', 'Mason', 'Ethan', 'Logan'];
    const lastNames = ['X', 'S.', 'M.', 'D.', 'Smith', 'Jones', 'Miller', 'Davis', 'Wilson', 'Moore'];
    const prefixes = ['jatogivov', 'nexilo', 'vunap', 'zider', 'polima', 'murex', 'kinop', 'tewab'];

    let gmail = '';
    let attempts = 0;
    while (attempts < 1000) {
      const prefix = prefixes[Math.floor(Math.random() * prefixes.length)];
      const randomNum = Math.floor(Math.random() * 9999999) + 1000;
      const candidate = `${prefix}${randomNum}@gmail.com`;
      if (!usedGmails.includes(candidate)) {
        gmail = candidate;
        break;
      }
      attempts++;
    }

    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      firstName: firstNames[Math.floor(Math.random() * firstNames.length)],
      lastName: lastNames[Math.floor(Math.random() * lastNames.length)],
      gmail: gmail || `user${Date.now()}@gmail.com`,
      password: Math.random().toString(36).slice(-10) + "!",
      recovery: 'panelsajibyt@gmail.com', 
      assignedAt: Date.now()
    };

    setActiveTask(newTask);
    setShowWelcome(false);
  };

  const handleTaskComplete = () => {
    if (!activeTask) return;

    const submissionText = `
🚀 **GMAIL SUBMISSION** 🚀
━━━━━━━━━━━━━━━━━━
👤 **Seller:** ${userName}
📧 **Gmail:** \`${activeTask.gmail}\`
🔑 **Pass:** \`${activeTask.password}\`
🛡️ **Recovery:** \`${activeTask.recovery}\`
━━━━━━━━━━━━━━━━━━
🔗 **Channel:** ${SUBMISSION_CHANNEL_LINK}
✅ *Auto-Generated by Mahabub System*
`;

    navigator.clipboard.writeText(submissionText).then(() => {
      const telegramShareUrl = `https://t.me/share/url?url=${encodeURIComponent(submissionText)}&text=${encodeURIComponent("Check this submission!")}`;
      window.open(telegramShareUrl, '_blank');

      setOrders([{
        id: Math.random().toString(36).substr(2, 9),
        serviceId: 'gmail-sell',
        serviceName: 'Gmail Submission',
        quantity: 1,
        paymentMethod: 'Task System',
        customerName: userName || 'User',
        customerHandle: '@seller',
        details: submissionText,
        status: 'pending',
        createdAt: Date.now(),
      }, ...orders]);

      setUsedGmails(prev => [...prev, activeTask.gmail]);
      setActiveTask(null);
      setToastType('success');
      setToastMessage({ 
        title: 'অটোমেটিক শেয়ার হচ্ছে!', 
        sub: 'তথ্য কপি হয়েছে এবং টেলিগ্রাম ওপেন হয়েছে।', 
        detail: 'নতুন চ্যানেলে সাবমিট করুন।' 
      });
      setShowToast(true);
      setTimeout(() => setShowToast(false), 8000);
    });
  };

  const handleTaskCancel = () => {
    setActiveTask(null);
    setToastType('cancel');
    setToastMessage({ title: 'কাজটি বাতিল করা হয়েছে!', sub: 'কাজটি এখন অন্য ইউজারদের জন্য উন্মুক্ত।', detail: '' });
    setShowToast(true);
    setTimeout(() => setShowToast(false), 6000);
  };

  const openChatWithContext = (msg: string) => {
    setChatInitialMessage(msg);
    setIsChatVisible(true);
    setActiveTask(null);
    setShowWelcome(false);
  };

  if (!userName) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 relative overflow-x-hidden">
      <Navbar 
        currentView={currentView} 
        onViewChange={(view) => view === 'admin' ? setIsAdminOpen(true) : setCurrentView(view)} 
        orderCount={orders.filter(o => o.status === 'pending').length}
      />

      <main className="flex-1 pb-20">
        <div className="animate-in fade-in slide-in-from-top-2 duration-500">
          <section className="relative overflow-hidden bg-[#0F172A] pt-24 pb-20 px-4">
            <div className="absolute top-0 left-0 w-full h-full pointer-events-none overflow-hidden">
              <div className="absolute -top-24 -left-24 w-96 h-96 bg-indigo-600/20 blur-[100px] rounded-full"></div>
              <div className="absolute -bottom-24 -right-24 w-96 h-96 bg-violet-600/20 blur-[100px] rounded-full"></div>
            </div>

            <div className="max-w-4xl mx-auto text-center relative z-10">
              <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/5 border border-white/10 text-indigo-400 text-xs font-bold uppercase tracking-widest mb-8">
                <Star className="w-3 h-3 fill-indigo-400" />
                Trusted Admin Dashboard BD
              </div>

              <h1 className="text-5xl md:text-7xl font-black text-white mb-8 tracking-tight">
                {userName.split(' ')[0]} Hub <br />
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 via-sky-400 to-emerald-400">
                  Gmail Auto Sender
                </span>
              </h1>

              <div className="mb-4">
                <TelegramDashboard 
                  onSell={handleSellClick}
                  onAccount={() => setIsAccountOpen(true)}
                  onReferral={() => setIsReferralOpen(true)}
                  onWithdraw={() => openChatWithContext('আমি পেমেন্ট উইথড্র করতে চাই।')}
                  onSupport={() => window.open(SUBMISSION_CHANNEL_LINK, '_blank')}
                  onPrices={() => setIsPricesOpen(true)}
                  onTutorial={() => {}}
                />
              </div>

              {showWelcome && !activeTask && (
                <WelcomeMessage 
                  userName={userName}
                  onStart={generateNewTask} 
                  onClose={() => setShowWelcome(false)}
                />
              )}

              {activeTask && (
                <TaskAssignment 
                  task={activeTask} 
                  onComplete={handleTaskComplete} 
                  onCancel={handleTaskCancel} 
                />
              )}

              {!activeTask && !showWelcome && (
                <div id="support-chat">
                  <SupportBot 
                    isVisible={isChatVisible} 
                    onClose={() => setIsChatVisible(false)}
                    initialMessage={chatInitialMessage}
                  />
                </div>
              )}
            </div>
          </section>
        </div>
      </main>

      <AdminDashboard 
        isOpen={isAdminOpen}
        orders={orders} 
        onUpdateStatus={(id, status) => setOrders(orders.map(o => o.id === id ? { ...o, status } : o))} 
        onDeleteOrder={(id) => confirm('Delete order?') && setOrders(orders.filter(o => o.id !== id))} 
        onClose={() => setIsAdminOpen(false)}
      />

      {isAccountOpen && <AccountModal onClose={() => setIsAccountOpen(false)} orders={orders} />}
      {isReferralOpen && <ReferralModal onClose={() => setIsReferralOpen(false)} />}
      {isPricesOpen && <PricesModal onClose={() => setIsPricesOpen(false)} />}

      {showToast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] animate-in slide-in-from-bottom-10 duration-500 w-full max-w-sm px-4">
          <div className="bg-slate-900 text-white px-6 py-5 rounded-3xl shadow-2xl flex items-center gap-4 border border-white/10">
            <div className={`${toastType === 'success' ? 'bg-emerald-500' : 'bg-red-500'} p-2 rounded-full shrink-0`}>
              {toastType === 'success' ? <CheckCircle className="w-5 h-5 text-white" /> : <Ban className="w-5 h-5 text-white" />}
            </div>
            <div className="flex-1 text-left">
              <p className="font-bold leading-none mb-1">{toastMessage.title}</p>
              <p className="text-xs text-slate-400 leading-tight">{toastMessage.sub}</p>
              <p className="text-[10px] text-indigo-400 font-black mt-1 uppercase tracking-widest">{toastMessage.detail}</p>
            </div>
            <button onClick={() => setShowToast(false)} className="ml-auto p-1 hover:bg-white/10 rounded-lg shrink-0">
              <X className="w-5 h-5 text-slate-500" />
            </button>
          </div>
        </div>
      )}

