import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import SupportBot from './components/SupportBot.tsx';
import TelegramDashboard from './components/TelegramDashboard.tsx';
import TaskAssignment from './components/TaskAssignment.tsx';
import WelcomeMessage from './components/WelcomeMessage.tsx';
import Login from './components/Login.tsx';
import { AccountModal, ReferralModal, PricesModal, TutorialModal } from './components/Modals.tsx';
import { Order, ViewState, Task } from './types.ts';
import { Star, Zap, CheckCircle, X, Ban } from 'lucide-react';

const App: React.FC = () => {
  const [userName, setUserName] = useState<string | null>(null);
  const [currentView, setCurrentView] = useState<ViewState>('store');
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [orders, setOrders] = useState<Order[]>([]);
  const [usedGmails, setUsedGmails] = useState<string[]>([]);

  const [showToast, setShowToast] = useState(false);
  const [toastType, setToastType] = useState<'success' | 'cancel'>('success');
  const [toastMessage, setToastMessage] = useState({ title: '', sub: '', detail: '' });

  // Task state
  const [activeTask, setActiveTask] = useState<Task | null>(null);
  const [showWelcome, setShowWelcome] = useState(false);

  // Chat integration state
  const [isChatVisible, setIsChatVisible] = useState(false);
  const [chatInitialMessage, setChatInitialMessage] = useState('');

  // Modal states
  const [isAccountOpen, setIsAccountOpen] = useState(false);
  const [isReferralOpen, setIsReferralOpen] = useState(false);
  const [isPricesOpen, setIsPricesOpen] = useState(false);
  const [isTutorialOpen, setIsTutorialOpen] = useState(false);

  const SUBMISSION_CHANNEL_LINK = "https://t.me/+R6VyXUcmkZg2YjNl";

  useEffect(() => {
    const savedName = localStorage.getItem('croma_user_name');
    if (savedName) setUserName(savedName);

    const savedOrders = localStorage.getItem('croma_orders');
    if (savedOrders) setOrders(JSON.parse(savedOrders));

    const savedGmails = localStorage.getItem('croma_used_gmails');
    if (savedGmails) setUsedGmails(JSON.parse(savedGmails));
  }, []);

  useEffect(() => {
    localStorage.setItem('croma_orders', JSON.stringify(orders));
  }, [orders]);

  useEffect(() => {
    localStorage.setItem('croma_used_gmails', JSON.stringify(usedGmails));
  }, [usedGmails]);

  const handleLogin = (name: string) => {
    setUserName(name);
    localStorage.setItem('croma_user_name', name);
  };

  const handleSellClick = () => {
    setShowWelcome(true);
    setActiveTask(null);
    setIsChatVisible(false);
  };

  const generateNewTask = () => {
    const firstNames = ['Cory', 'Ryan', 'Liam', 'Noah', 'James', 'Oliver', 'Lucas', 'Mason', 'Ethan', 'Logan'];
    const lastNames = ['X', 'S.', 'M.', 'D.', 'Smith', 'Jones', 'Miller', 'Davis', 'Wilson', 'Moore'];
    const prefixes = ['jatogivov', 'nexilo', 'vunap', 'zider', 'polima', 'murex', 'kinop', 'tewab'];

    let gmail = '';
    let attempts = 0;
    while (attempts < 1000) {
      const prefix = prefixes[Math.floor(Math.random() * prefixes.length)];
      const randomNum = Math.floor(Math.random() * 9999999) + 1000;
      const candidate = `${prefix}${randomNum}@gmail.com`;
      if (!usedGmails.includes(candidate)) {
        gmail = candidate;
        break;
      }
      attempts++;
    }

    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      firstName: firstNames[Math.floor(Math.random() * firstNames.length)],
      lastName: lastNames[Math.floor(Math.random() * lastNames.length)],
      gmail: gmail || `user${Date.now()}@gmail.com`,
      password: Math.random().toString(36).slice(-10) + "!",
      recovery: 'panelsajibyt@gmail.com', 
      assignedAt: Date.now()
    };

    setActiveTask(newTask);
    setShowWelcome(false);
  };

  const handleTaskComplete = () => {
    if (!activeTask) return;

    const submissionText = `
🚀 **GMAIL SUBMISSION** 🚀
━━━━━━━━━━━━━━━━━━
👤 **Seller:** ${userName}
📧 **Gmail:** \`${activeTask.gmail}\`
🔑 **Pass:** \`${activeTask.password}\`
🛡️ **Recovery:** \`${activeTask.recovery}\`
━━━━━━━━━━━━━━━━━━
🔗 **Channel:** ${SUBMISSION_CHANNEL_LINK}
✅ *Auto-Generated by Mahabub System*
`;

    navigator.clipboard.writeText(submissionText).then(() => {
      const telegramShareUrl = `https://t.me/share/url?url=${encodeURIComponent(submissionText)}&text=${encodeURIComponent("Check this submission!")}`;
      window.open(telegramShareUrl, '_blank');

      setOrders([{
        id: Math.random().toString(36).substr(2, 9),
        serviceId: 'gmail-sell',
        serviceName: 'Gmail Submission',
        quantity: 1,
        paymentMethod: 'Task System',
        customerName: userName || 'User',
        customerHandle: '@seller',
        details: submissionText,
        status: 'pending',
        createdAt: Date.now(),
      }, ...orders]);

      setUsedGmails(prev => [...prev, activeTask.gmail]);
      setActiveTask(null);
      setToastType('success');
      setToastMessage({ 
        title: 'অটোমেটিক শেয়ার হচ্ছে!', 
        sub: 'তথ্য কপি হয়েছে এবং টেলিগ্রাম ওপেন হয়েছে।', 
        detail: 'নতুন চ্যানেলে সাবমিট করুন।' 
      });
      setShowToast(true);
      setTimeout(() => setShowToast(false), 8000);
    });
  };

  const handleTaskCancel = () => {
    setActiveTask(null);
    setToastType('cancel');
    setToastMessage({ title: 'কাজটি বাতিল করা হয়েছে!', sub: 'কাজটি এখন অন্য ইউজারদের জন্য উন্মুক্ত।', detail: '' });
    setShowToast(true);
    setTimeout(() => setShowToast(false), 6000);
  };

  const openChatWithContext = (msg: string) => {
    setChatInitialMessage(msg);
    setIsChatVisible(true);
    setActiveTask(null);
    setShowWelcome(false);
  };

  if (!userName) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 relative overflow-x-hidden">
      <Navbar 
        currentView={currentView} 
        onViewChange={(view) => view === 'admin' ? setIsAdminOpen(true) : setCurrentView(view)} 
        orderCount={orders.filter(o => o.status === 'pending').length}
      />

      <main className="flex-1 pb-20">
        <div className="animate-in fade-in slide-in-from-top-2 duration-500">
          <section className="relative overflow-hidden bg-[#0F172A] pt-24 pb-20 px-4">
            <div className="absolute top-0 left-0 w-full h-full pointer-events-none overflow-hidden">
              <div className="absolute -top-24 -left-24 w-96 h-96 bg-indigo-600/20 blur-[100px] rounded-full"></div>
              <div className="absolute -bottom-24 -right-24 w-96 h-96 bg-violet-600/20 blur-[100px] rounded-full"></div>
            </div>

            <div className="max-w-4xl mx-auto text-center relative z-10">
              <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/5 border border-white/10 text-indigo-400 text-xs font-bold uppercase tracking-widest mb-8">
                <Star className="w-3 h-3 fill-indigo-400" />
                Trusted Admin Dashboard BD
              </div>

              <h1 className="text-5xl md:text-7xl font-black text-white mb-8 tracking-tight">
                {userName.split(' ')[0]} Hub <br />
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 via-sky-400 to-emerald-400">
                  Gmail Auto Sender
                </span>
              </h1>

              <div className="mb-4">
                <TelegramDashboard 
                  onSell={handleSellClick}
                  onAccount={() => setIsAccountOpen(true)}
                  onReferral={() => setIsReferralOpen(true)}
                  onWithdraw={() => openChatWithContext('আমি পেমেন্ট উইথড্র করতে চাই।')}
                  onSupport={() => window.open(SUBMISSION_CHANNEL_LINK, '_blank')}
                  onPrices={() => setIsPricesOpen(true)}
                  onTutorial={() => setIsTutorialOpen(true)}
                />
              </div>

              {showWelcome && !activeTask && (
                <WelcomeMessage 
                  userName={userName}
                  onStart={generateNewTask} 
                  onClose={() => setShowWelcome(false)}
                />
              )}

              {activeTask && (
                <TaskAssignment 
                  task={activeTask} 
                  onComplete={handleTaskComplete} 
                  onCancel={handleTaskCancel} 
                />
              )}

              {!activeTask && !showWelcome && (
                <div id="support-chat">
                  <SupportBot 
                    isVisible={isChatVisible} 
                    onClose={() => setIsChatVisible(false)}
                    initialMessage={chatInitialMessage}
                  />
                </div>
              )}
            </div>
          </section>
        </div>
      </main>

      <AdminDashboard 
        isOpen={isAdminOpen}
        orders={orders} 
        onUpdateStatus={(id, status) => setOrders(orders.map(o => o.id === id ? { ...o, status } : o))} 
        onDeleteOrder={(id) => confirm('Delete order?') && setOrders(orders.filter(o => o.id !== id))} 
        onClose={() => setIsAdminOpen(false)}
      />

      {isAccountOpen && <AccountModal onClose={() => setIsAccountOpen(false)} orders={orders} />}
      {isReferralOpen && <ReferralModal onClose={() => setIsReferralOpen(false)} />}
      {isPricesOpen && <PricesModal onClose={() => setIsPricesOpen(false)} />}
      {isTutorialOpen && <TutorialModal onClose={() => setIsTutorialOpen(false)} />}

      {showToast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] animate-in slide-in-from-bottom-10 duration-500 w-full max-w-sm px-4">
          <div className="bg-slate-900 text-white px-6 py-5 rounded-3xl shadow-2xl flex items-center gap-4 border border-white/10">
            <div className={`${toastType === 'success' ? 'bg-emerald-500' : 'bg-red-500'} p-2 rounded-full shrink-0`}>
              {toastType === 'success' ? <CheckCircle className="w-5 h-5 text-white" /> : <Ban className="w-5 h-5 text-white" />}
            </div>
            <div className="flex-1 text-left">
              <p className="font-bold leading-none mb-1">{toastMessage.title}</p>
              <p className="text-xs text-slate-400 leading-tight">{toastMessage.sub}</p>
              <p className="text-[10px] text-indigo-400 font-black mt-1 uppercase tracking-widest">{toastMessage.detail}</p>
            </div>
            <button onClick={() => setShowToast(false)} className="ml-auto p-1 hover:bg-white/10 rounded-lg shrink-0">
              <X className="w-5 h-5 text-slate-500" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  CheckCircle, Clock, Trash2, AlertCircle, ChevronRight, Zap, Copy, 
  ChevronDown, ChevronUp, Mail, Key, ShieldAlert, Landmark, Lock,
  ArrowRight
} from 'lucide-react';
import { Order } from '../types.ts';

interface AdminDashboardProps {
  isOpen: boolean;
  orders: Order[];
  onUpdateStatus: (id: string, status: Order['status']) => void;
  onDeleteOrder: (id: string) => void;
  onClose: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ isOpen, orders, onUpdateStatus, onDeleteOrder, onClose }) => {
  const [isAuthorized, setIsAuthorized] = useState(false);
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState(false);

  const [expandedOrderId, setExpandedOrderId] = useState<string | null>(null);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  // Reset authorization on panel close to keep it secure
  useEffect(() => {
    if (!isOpen) {
      setPassword('');
      setAuthError(false);
      // Optional: keep authorized for the session. If you want true security, uncomment next line:
      // setIsAuthorized(false);
    }
  }, [isOpen]);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === '990') {
      setIsAuthorized(true);
      setAuthError(false);
    } else {
      setAuthError(true);
      setPassword('');
      setTimeout(() => setAuthError(false), 2000);
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const parseCredentials = (details: string) => {
    const gmailMatch = details.match(/📧 \*\*Gmail:\*\* `([^`]+)`/);
    const passMatch = details.match(/🔑 \*\*Pass:\*\* `([^`]+)`/);
    const recoveryMatch = details.match(/🛡️ \*\*Recovery:\*\* `([^`]+)`/);

    return {
      gmail: gmailMatch ? gmailMatch[1] : 'N/A',
      password: passMatch ? passMatch[1] : 'N/A',
      recovery: recoveryMatch ? recoveryMatch[1] : 'N/A'
    };
  };

  return (
    <>
      <div 
        className={`fixed inset-0 z-[60] bg-black/60 backdrop-blur-sm transition-opacity duration-300 ${
          isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'
        }`}
        onClick={onClose}
      />

      <div 
        className={`fixed top-0 right-0 h-full z-[70] w-full max-w-4xl bg-white shadow-2xl transition-transform duration-500 ease-in-out transform ${
          isOpen ? 'translate-x-0' : 'translate-x-full'
        }`}
      >
        {!isAuthorized ? (
          /* Password Gate */
          <div className="h-full flex flex-col items-center justify-center p-8 bg-[#0F172A] relative overflow-hidden">
            {/* Background Decoration */}
            <div className="absolute top-0 right-0 w-full h-full pointer-events-none opacity-20">
              <div className="absolute -top-24 -right-24 w-64 h-64 bg-indigo-500 blur-[80px] rounded-full"></div>
              <div className="absolute bottom-48 -left-24 w-48 h-48 bg-violet-500 blur-[60px] rounded-full"></div>
            </div>

            <div className="w-full max-w-sm relative z-10 text-center">
               <div className="mb-8">
                  <div className="w-20 h-20 bg-indigo-500/10 border border-indigo-500/20 rounded-3xl flex items-center justify-center mx-auto mb-4">
                    <Lock className="w-10 h-10 text-indigo-400" />
                  </div>
                  <h3 className="text-2xl font-black text-white mb-2 uppercase tracking-tight">Admin Authentication</h3>
                  <p className="text-sm text-indigo-300/50 font-medium italic">Please enter the security PIN to access orders.</p>
               </div>

               <form onSubmit={handleAuth} className="space-y-4">
                  <div className="relative group">
                    <Key className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-indigo-500/40" />
                    <input 
                      autoFocus
                      type="password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder="ENTER PIN..."
                      className={`w-full bg-white/5 border-2 rounded-2xl py-5 pl-12 pr-4 text-white text-center text-3xl tracking-[1em] font-black focus:outline-none transition-all ${
                        authError ? 'border-rose-500/50' : 'border-white/10 focus:border-indigo-500/50 focus:bg-white/10'
                      }`}
                    />
                  </div>
                  {authError && (
                    <div className="flex items-center justify-center gap-2 text-rose-400 text-xs font-bold animate-pulse">
                      <AlertCircle className="w-4 h-4" />
                      ACCESS DENIED!
                    </div>
                  )}
                  <button 
                    type="submit"
                    className="w-full py-5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-black text-lg transition-all shadow-xl shadow-indigo-500/20 flex items-center justify-center gap-3"
                  >
                    <span>AUTHORIZE</span>
                    <ArrowRight className="w-5 h-5" />
                  </button>
               </form>

               <button 
                onClick={onClose}
                className="mt-12 text-xs font-black text-white/20 uppercase tracking-[0.4em] hover:text-white/40 transition-colors"
               >
                 Go Back
               </button>
            </div>
          </div>
        ) : (
          /* Main Dashboard Content */
          <div className="h-full flex flex-col">
            <div className="p-6 border-b border-gray-100 flex items-center justify-between bg-slate-50/50">
              <div className="flex items-center gap-4">
                <button 
                  onClick={onClose}
