                >
                  <ChevronRight className="w-6 h-6" />
                </button>
                <div>
                  <h1 className="text-2xl font-black text-gray-900">Admin Panel</h1>
                  <p className="text-xs text-indigo-600 font-bold uppercase tracking-widest">Management System v2.0</p>
                </div>
              </div>
              <button 
                onClick={() => setIsAuthorized(false)}
                className="text-[10px] font-black text-rose-500 bg-rose-50 px-3 py-1 rounded-lg uppercase tracking-widest hover:bg-rose-100 transition-colors"
              >
                Logout
