          <div className="space-y-1 bg-slate-50/50 rounded-2xl p-2 border border-slate-100">
             <div className="flex items-center gap-2 p-4">
                <div className="text-indigo-500"><User className="w-5 h-5" /></div>
                <div className="flex flex-col">
                   <p className="text-sm font-bold text-gray-800">First Name:- <span className="font-mono text-slate-600 ml-1">{task.firstName}</span></p>
                   <p className="text-sm font-bold text-gray-800">Last Name:- <span className="font-mono text-slate-600 ml-1">{task.lastName}</span></p>
                </div>
             </div>

            <FieldRow 
              label="Gmail" 
              value={task.gmail} 
              icon={<Mail className="w-5 h-5" />} 
              copyable 
              fieldId="gmail"
